17	  it("should return 85 G for a single staff", () => {
18	    expect(quote([{ type: "staff" }])).toBe(85);
19	  });
20	  it("should return base premium for single potion without modifiers", () => {
21	    expect(quote([{ type: "potion" }])).toBe(45);
22	  });
23	  it("should return base premium for single component without modifiers", () => {
24	    expect(quote([{ type: "component" }])).toBe(35);
25	  });
26	
27	  // Single item with cursed modifier
28	  it("should apply 50% cursed surcharge to single sword", () => {
29	    expect(quote([{ type: "sword", cursed: true }])).toBe(155);
30	  });
31	  it("should apply 50% cursed surcharge to single component", () => {
32	    expect(quote([{ type: "component", cursed: true }])).toBe(53);
33	  });
34	
35	  // Single item with enchantment modifier
36	  it("should apply 30% enchantment surcharge for level 5 item", () => {
37	    expect(quote([{ type: "sword", enchantment: 5 }])).toBe(137);
38	  });
39	  it("should apply 30% enchantment surcharge for level 8 item", () => {
40	    expect(quote([{ type: "sword", enchantment: 8 }])).toBe(137);
41	  });
42	
43	  // Multiple items of same type
44	  it("should return 210 G for two swords", () => {
45	    expect(quote([{ type: "sword" }, { type: "sword" }])).toBe(210);
46	  });
47	  it("should sum premiums for two components without modifiers", () => {
48	    expect(quote([{ type: "component" }, { type: "component" }])).toBe(70);
49	  });
50	  it("should return 60 G for three components instead of 75 G", () => {
51	    expect(quote([{ type: "component" }, { type: "component" }, { type: "component" }])).toBe(60);
52	  });
53	
54	  // Multiple items of different types
55	  it("should sum premiums for sword and amulet without modifiers", () => {
56	    expect(quote([{ type: "sword" }, { type: "amulet" }])).toBe(170);
57	  });
58	  it("should sum premiums for sword, amulet, and staff without modifiers", () => {
59	    expect(quote([{ type: "sword" }, { type: "amulet" }, { type: "staff" }])).toBe(260);
60	  });
61	
62	  // Processing fee
63	  it.todo("should add 5 G processing fee to empty quote");
64	  it.todo("should add 5 G processing fee to single item quote");
65	  it.todo("should add 5 G processing fee to multi-item quote");
66	
67	  // Policy-wide modifiers: First insurance surcharge
68	  it.todo("should apply 10% first insurance surcharge to single item");
69	  it.todo("should apply 10% first insurance surcharge to multiple items");
70	
71	  // Policy-wide modifiers: Follow-up contract discount
72	  it.todo("should apply 15% follow-up contract discount to single item");
73	  it.todo("should apply 15% follow-up contract discount to multiple items");
74	
75	  // Policy-wide modifiers: Long-standing customer discount
76	  it.todo("should apply 20% long-standing customer discount to single item");
77	  it.todo("should apply 20% long-standing customer discount to multiple items");
78	
79	  // Combined modifiers: cursed + enchantment
80	  it("should apply both cursed and enchantment surcharges to same item", () => {
81	    expect(quote([{ type: "sword", cursed: true, enchantment: 5 }])).toBe(206);
82	  });
83	
84	  // Combined modifiers: item-level + policy-level
85	  it.todo("should apply cursed surcharge then first insurance surcharge");
86	  it.todo("should apply enchantment surcharge then follow-up contract discount");
87	
88	  // Rounding up in MHPCO's favor
89	  it.todo("should round up fractional premium to whole number");
90	  it.todo("should round up after applying all modifiers");
91	});
